import React from 'react'
import { Link } from 'react-router-dom'

export default function Room(props) {
    let room= props.room
    let roomname="/"+room.name

  return (
    <div color={room.color}><Link to={roomname}>
        <h1>room.name</h1>
        </Link>
    </div>
  )
}
